import { useEffect, useState } from "react";
import { useParams, useNavigate } from "react-router-dom";
import API from "../services/api";

function PlayerDetails() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [player, setPlayer] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    const fetchPlayer = async () => {
      try {
        const res = await API.get(`/players/${id}`);
        setPlayer(res.data);
      } catch (err) {
        setError("Player not found or error fetching details.");
        console.error(err);
      } finally {
        setLoading(false);
      }
    };
    fetchPlayer();
  }, [id]);

  if (loading) return <div className="page"><p>Loading player details...</p></div>;
  if (error) return <div className="page"><p style={{ color: 'red' }}>{error}</p></div>;
  if (!player) return <div className="page"><p>Player not found.</p></div>;

  return (
    <div className="page">
      <button onClick={() => navigate(-1)} className="login-btn" style={{ width: 'auto', marginBottom: '20px', padding: '8px 16px' }}>
        ← Back to Players
      </button>

      <div className="player-profile-card" style={{ maxWidth: '800px', margin: '0 auto' }}>
        <div className="profile-header">
          <div style={{ display: 'flex', gap: '10px', alignItems: 'center', marginBottom: '10px' }}>
             <span style={{ fontSize: '1.5rem' }}>🇮🇳</span>
             <span style={{ fontSize: '1rem', fontWeight: 'bold', textTransform: 'uppercase', color: 'var(--cyan)' }}>{player.team}</span>
          </div>
          <div className="profile-name" style={{ fontSize: '2.5rem' }}>{player.name}</div>
          <div className="profile-role" style={{ fontSize: '1.2rem' }}>
            <span style={{ color: 'var(--cyan)' }}>≫</span> {player.role}
          </div>
        </div>

        <div className="stats-container" style={{ gridTemplateColumns: 'repeat(auto-fit, minmax(150px, 1fr))', gap: '20px', marginTop: '30px' }}>
          <div className="stat-item">
            <div className="stat-label">MATCHES</div>
            <div className="stat-value">{player.matches}</div>
          </div>
          <div className="stat-item">
            <div className="stat-label">RUNS</div>
            <div className="stat-value">{player.runs}</div>
          </div>
          <div className="stat-item">
            <div className="stat-label">AVERAGE</div>
            <div className="stat-value">{player.battingAvg}</div>
          </div>
          <div className="stat-item">
            <div className="stat-label">STRIKE RATE</div>
            <div className="stat-value">{player.strikeRate}</div>
          </div>
          <div className="stat-item">
            <div className="stat-label">50s / 100s</div>
            <div className="stat-value">{player.fifties || 0} / {player.hundreds || 0}</div>
          </div>
          <div className="stat-item">
            <div className="stat-label">HIGHEST SCORE</div>
            <div className="stat-value">{player.highScore}*</div>
          </div>
          <div className="stat-item">
            <div className="stat-label">WICKETS</div>
            <div className="stat-value">{player.wickets || 0}</div>
          </div>
          <div className="stat-item">
            <div className="stat-label">BEST BOWLING</div>
            <div className="stat-value">{player.bestBowling || "N/A"}</div>
          </div>
        </div>

        <div style={{ marginTop: '40px', padding: '20px', background: 'rgba(255,255,255,0.05)', borderRadius: '10px' }}>
            <h3 style={{ color: 'var(--cyan)', marginBottom: '15px' }}>Player Information</h3>
            <p><strong>Team:</strong> {player.team}</p>
            <p><strong>Role:</strong> {player.role}</p>
            <p><strong>Description:</strong> {player.description || "No description available for this player."}</p>
        </div>
      </div>
    </div>
  );
}

export default PlayerDetails;
